    "mcp": true,
    "retry": true,
    "staleBranchThreshold": 5,
    "pmRun": "npm run",
    "devUrl": "http://localhost:3000"
  },
  "agents": {
    "parallel": false,
    "model": "haiku"
  },
  "scopeAssessment": {
    "enabled": true,
    "skipIfSimple": true,
    "trivialThresholds": {
      "maxACItems": 3,
      "maxDirectories": 1
    },
    "thresholds": {
      "featureCount": {
        "yellow": 2,
        "red": 3
      },
      "acItems": {
        "yellow": 6,
        "red": 9
      },
      "fileEstimate": {
        "yellow": 8,
        "red": 13
      },
      "directorySpread": {
        "yellow": 3,
        "red": 5
      }
    }
  }
}

